/* ── Expiry urgency helpers ── */
function getExpiryUrgency(expiryUtc: string): { color: string; label: string; flash: boolean } {
  const now = Date.now();
  const expiry = new Date(expiryUtc).getTime();
  const diff = expiry - now;
  if (diff <= 0) return { color: "#6b7280", label: "Expired", flash: false };
  const mins = diff / 60000;
  if (mins <= 5) return { color: "#ef4444", label: "< 5 min", flash: true };
  if (mins <= 15) return { color: "#f97316", label: "< 15 min", flash: true };
  if (mins <= 60) return { color: "#eab308", label: "< 1 hr", flash: false };
  return { color: "#9ca3af", label: "", flash: false };
}

