function StatusCellRenderer(params: ICellRendererParams<Order>) {
  const order = params.data;
  if (!order) return null;
  const status = order.status;
  const color = statusColors[status] || "#9ca3af";
  const counterCount = order.counterOfferCount;
  const showCounter = counterCount > 0 && status === "Countered";
  return (
    <span style={{ color, fontWeight: 600, fontSize: "0.8rem" }}>
      {status}
      {showCounter && (
        <span style={{ color: counterCount >= MAX_COUNTER_OFFERS ? "#ef4444" : "#eab308", marginLeft: 4, fontSize: "0.7rem" }}>
          ({counterCount}/{MAX_COUNTER_OFFERS}{counterCount >= MAX_COUNTER_OFFERS ? " FINAL" : ""})
        </span>
      )}
    </span>
  );
}

function OrderTypeCellRenderer(params: ICellRendererParams<Order>) {
  const type = params.value as OrderType;
  const colors = tradeTypeColors[type] || { bg: "#374151", text: "#e8eaed" };
  return (
    <Chip
      label={type}
      size="small"
      sx={{
        bgcolor: colors.bg,
        color: colors.text,
        height: 20,
        fontSize: "0.7rem",
        fontWeight: 600,
      }}
    />
  );
}

function PendingWithCellRenderer(params: ICellRendererParams<Order>) {
  const val = params.value as string;
  if (!val || val === "\u2014") {
    return <span style={{ color: "#6b7280", fontSize: "0.8rem" }}>{val}</span>;
  }
  return (
    <span style={{ color: "#f59e0b", fontWeight: 500, fontSize: "0.8rem" }}>
      {val}
    </span>
  );
}

function ExpiryCellRenderer(params: ICellRendererParams<Order>) {
  if (!params.data || !params.data.orderExpiryUtc) return null;
  const raw = params.data.orderExpiryUtc;
  const isNew = params.data.status === "New";

  // For New rows, show the duration label (e.g. "15 min") or formatted custom time
  if (isNew) {
    const isPreset = EXPIRY_PRESETS.some((p) => p.label === raw);
    if (isPreset) {
      return <span style={{ color: "#93c5fd", fontSize: "0.8rem", fontWeight: 500 }}>{raw}</span>;
    }
    // Custom ISO — show formatted
    if (!isNaN(Date.parse(raw))) {
      const d = new Date(raw);
      const h = d.getHours(); const ampm = h >= 12 ? "PM" : "AM";
      const hh = String(h % 12 || 12).padStart(2, "0");
      const mm = String(d.getMinutes()).padStart(2, "0");
      const dateStr = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
      return <span style={{ color: "#93c5fd", fontSize: "0.8rem", fontWeight: 500 }}>{dateStr} {hh}:{mm} {ampm}</span>;
    }
    return <span style={{ color: "#6b7280", fontSize: "0.8rem" }}>{raw}</span>;
  }

  // For submitted/existing rows — show timestamp with urgency
  const urgency = getExpiryUrgency(raw);
  const d = new Date(raw);
  const h = d.getHours();
  const ampm = h >= 12 ? "PM" : "AM";
  const hh = String(h % 12 || 12).padStart(2, "0");
  const mm = String(d.getMinutes()).padStart(2, "0");
  const dateStr = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
  const timeStr = `${hh}:${mm} ${ampm}`;
  const isTerminal = ["Booked","Failed","Expired","Cancelled","Rejected"].includes(params.data.status);

  return (
    <span
      style={{
        color: isTerminal ? "#6b7280" : urgency.color,
        fontWeight: isTerminal ? 400 : (urgency.flash ? 700 : 500),
        fontSize: "0.8rem",
        animation: urgency.flash && !isTerminal ? "expiry-pulse 1s ease-in-out infinite" : undefined,
      }}
    >
      {dateStr} {timeStr}
      {urgency.label && !isTerminal && (
        <span style={{ marginLeft: 4, fontSize: "0.65rem", opacity: 0.9 }}>
          {urgency.label}
        </span>
      )}
    </span>
  );
}

