/* ── Custom Expiry Cell Editor ── */
const EXPIRY_PRESETS = [
  { label: "15 min", minutes: 15 },
  { label: "30 min", minutes: 30 },
  { label: "1 hour", minutes: 60 },
  { label: "2 hours", minutes: 120 },
  { label: "EOD", minutes: -1 },
] as const;

/** Resolve an expiry label ("15 min", "EOD", or ISO string) to an actual ISO timestamp */
function resolveExpiryToIso(label: string): string {
  const preset = EXPIRY_PRESETS.find((p) => p.label === label);
  if (preset) {
    if (preset.minutes === -1) {
      const eod = new Date(); eod.setHours(17, 0, 0, 0);
      if (eod.getTime() <= Date.now()) eod.setDate(eod.getDate() + 1);
      return eod.toISOString();
    }
    return new Date(Date.now() + preset.minutes * 60 * 1000).toISOString();
  }
  // Already an ISO string or custom datetime
  if (label && !isNaN(Date.parse(label))) return new Date(label).toISOString();
  // Fallback: +15 min
  return new Date(Date.now() + 15 * 60 * 1000).toISOString();
}

const ExpiryCellEditor = forwardRef((props: ICellEditorParams, ref) => {
  const [value, setValue] = useState<string>(props.value || "15 min");
  const [showCustom, setShowCustom] = useState(false);
  const refInput = useRef<HTMLInputElement>(null);

  useImperativeHandle(ref, () => ({
    getValue: () => value,
    isCancelAfterEnd: () => !value,
  }));

  useEffect(() => { if (showCustom && refInput.current) refInput.current.focus(); }, [showCustom]);

  const selectPreset = (label: string) => {
    setValue(label);
    setTimeout(() => props.stopEditing(), 0);
  };

  const confirmCustom = () => {
    if (refInput.current?.value) {
      const d = new Date(refInput.current.value);
      setValue(d.toISOString());
      setTimeout(() => props.stopEditing(), 0);
    }
  };

  const defaultDT = (() => {
    const d = value && !isNaN(Date.parse(value)) && !EXPIRY_PRESETS.some(p => p.label === value)
      ? new Date(value) : new Date(Date.now() + 15 * 60000);
    return d.toISOString().slice(0, 16);
  })();

  return (
    <div style={{ padding: 8, background: "#1e293b", border: "1px solid #334155", borderRadius: 6, width: 220, zIndex: 999 }}>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 4, marginBottom: 6 }}>
        {EXPIRY_PRESETS.map((p) => (
          <button
            key={p.label}
            onClick={() => selectPreset(p.label)}
            style={{ padding: "3px 8px", fontSize: 11, borderRadius: 4, border: value === p.label ? "1px solid #60a5fa" : "1px solid #475569", background: value === p.label ? "#1e3a5f" : "#334155", color: value === p.label ? "#93c5fd" : "#e2e8f0", cursor: "pointer", fontWeight: value === p.label ? 700 : 400 }}
          >
            {p.label}
          </button>
        ))}
      </div>
      {!showCustom ? (
        <button
          onClick={() => setShowCustom(true)}
          style={{ width: "100%", padding: "4px 8px", fontSize: 11, borderRadius: 4, border: "1px solid #475569", background: "#1e3a5f", color: "#93c5fd", cursor: "pointer" }}
        >
          Custom time...
        </button>
      ) : (
        <div style={{ display: "flex", gap: 4 }}>
          <input
            ref={refInput}
            type="datetime-local"
            defaultValue={defaultDT}
            style={{ flex: 1, fontSize: 11, padding: "3px 4px", borderRadius: 4, border: "1px solid #475569", background: "#0f172a", color: "#e2e8f0" }}
            onKeyDown={(e) => { if (e.key === "Enter") confirmCustom(); }}
          />
          <button
            onClick={confirmCustom}
            style={{ padding: "3px 8px", fontSize: 11, borderRadius: 4, border: "1px solid #475569", background: "#166534", color: "#bbf7d0", cursor: "pointer" }}
          >
            OK
          </button>
        </div>
      )}
    </div>
  );
});

/** Check if a cell value is "empty" for mandatory validation */
function isMandatoryEmpty(value: unknown): boolean {
  if (value == null) return true;
  if (typeof value === "string" && value.trim() === "") return true;
  if (typeof value === "number" && value === 0) return true;
  return false;
}

